// ─── TYPING ───────────────────────────────────────────────────────────────────
function Typing({ texts }) {
  const [out,setOut]=useState(""); const [idx,setIdx]=useState(0); const [c,setC]=useState(0); const [del,setDel]=useState(false);
  useEffect(()=>{ const cur=texts[idx]; let t;
    if(!del&&c<cur.length) t=setTimeout(()=>setC(x=>x+1),65);
    else if(!del&&c===cur.length) t=setTimeout(()=>setDel(true),2200);
    else if(del&&c>0) t=setTimeout(()=>setC(x=>x-1),35);
    else{setDel(false);setIdx(x=>(x+1)%texts.length);}
    setOut(cur.slice(0,c)); return()=>clearTimeout(t);
  },[c,del,idx,texts]);
  return <span style={{color:"#8896b3",fontWeight:300}}>{out}<span style={{display:"inline-block",width:2,height:"1.1em",background:"#e8c547",marginLeft:3,verticalAlign:"text-bottom",animation:"blink 1s step-end infinite"}}/></span>;
}

